{
  "prototype_name": "Castle Clashers Playable Ad",
  "implementation_summary": "A portrait-oriented 2D tower defense playable where the user drags a weapon unit from a bottom UI panel onto a designated slot on their castle. Once placed, the unit automatically fires projectiles at the enemy castle. The enemy castle fires back automatically. The game ends when either castle's health reaches zero.",
  "screen": {
    "orientation": "portrait",
    "logical_width": 720,
    "logical_height": 1280,
    "responsive_strategy": "Scale-to-fit (object-fit: contain or canvas scaling) centered in the viewport, ensuring the bottom UI and both castles remain visible."
  },
  "gameplay": {
    "objective": "Destroy the enemy castle before the player's castle is destroyed.",
    "primary_interaction": "Drag and drop a unit card from the bottom UI onto a valid slot on the player's castle.",
    "win_condition": "Enemy castle health reaches 0.",
    "loss_or_timeout_condition": "Player castle health reaches 0.",
    "session_length_seconds": 15
  },
  "entities": [
    {
      "id": "player_castle",
      "role": "Player's base",
      "asset": "Blue Castle.png",
      "behavior": "Stationary at the bottom-left. Has a health bar. Contains a visual 'drop zone' slot for the player to place a unit.",
      "priority": "must"
    },
    {
      "id": "enemy_castle",
      "role": "Enemy base",
      "asset": "Red Castle.png",
      "behavior": "Stationary at the top-right. Has a health bar. Automatically spawns enemy projectiles aimed at the player castle on a fixed timer.",
      "priority": "must"
    },
    {
      "id": "deployable_unit",
      "role": "Player's weapon/defender",
      "asset": "Weapon_1.png",
      "behavior": "Starts in the bottom UI. Draggable. When dropped on the player castle's drop zone, it snaps into place and begins auto-firing projectiles at the enemy castle.",
      "priority": "must"
    },
    {
      "id": "player_projectile",
      "role": "Damage dealer for player",
      "asset": "Projectile_1.png",
      "behavior": "Spawns from the deployed unit, travels in an arc or straight line to the enemy castle, reduces enemy health on impact, and triggers a particle/shake effect.",
      "priority": "must"
    },
    {
      "id": "enemy_projectile",
      "role": "Damage dealer for enemy",
      "asset": "Projectile_2.png",
      "behavior": "Spawns from the enemy castle, travels to the player castle, reduces player health on impact.",
      "priority": "must"
    }
  ],
  "asset_plan": [
    {
      "asset_path": "Background.png",
      "use": "Game background",
      "processing": "Scale and crop to fill the portrait canvas.",
      "required": true
    },
    {
      "asset_path": "Blue Castle.png",
      "use": "Player base sprite",
      "processing": "Scale down to fit bottom-left quadrant.",
      "required": true
    },
    {
      "asset_path": "Red Castle.png",
      "use": "Enemy base sprite",
      "processing": "Scale down to fit top-right quadrant.",
      "required": true
    },
    {
      "asset_path": "Weapon_1.png",
      "use": "Draggable unit icon and deployed turret sprite",
      "processing": "Use as the primary deployable unit to avoid PSB conversion issues in browser.",
      "required": true
    },
    {
      "asset_path": "Projectile_1.png",
      "use": "Player projectile sprite",
      "processing": "Scale down appropriately.",
      "required": true
    },
    {
      "asset_path": "Projectile_2.png",
      "use": "Enemy projectile sprite",
      "processing": "Scale down appropriately.",
      "required": true
    },
    {
      "asset_path": "Sfx.wav",
      "use": "Impact and firing sound effect",
      "processing": "Base64 encode into the HTML file.",
      "required": false
    }
  ],
  "interaction_flow": [
    {
      "step": 1,
      "player_action": "None (Idle)",
      "system_response": "Show a pulsing hand cursor prompting the user to drag the weapon from the bottom UI to the glowing slot on the Blue Castle. Enemy castle begins firing slowly to create urgency."
    },
    {
      "step": 2,
      "player_action": "Pointer down and drag on the weapon card",
      "system_response": "Weapon sprite follows the pointer. Tutorial hand disappears."
    },
    {
      "step": 3,
      "player_action": "Pointer up over the Blue Castle slot",
      "system_response": "Weapon snaps to the slot. Bottom UI card is grayed out or disappears. Weapon immediately fires its first projectile."
    },
    {
      "step": 4,
      "player_action": "None (Auto-battling)",
      "system_response": "Deployed weapon fires every X seconds. Projectiles hit castles, updating health bars and triggering screen shake/flash."
    },
    {
      "step": 5,
      "player_action": "None (End state)",
      "system_response": "When a health bar hits 0, the losing castle fades/explodes. Show 'Download Now' CTA overlay."
    }
  ],
  "parameters": [
    {
      "name": "player_fire_rate_ms",
      "type": "number",
      "default": 800,
      "variation_range": "500-1500",
      "gameplay_effect": "Determines how fast the player deals damage after deployment."
    },
    {
      "name": "enemy_fire_rate_ms",
      "type": "number",
      "default": 1200,
      "variation_range": "1000-2000",
      "gameplay_effect": "Controls the pressure and difficulty."
    },
    {
      "name": "player_damage_per_hit",
      "type": "number",
      "default": 20,
      "variation_range": "10-34",
      "gameplay_effect": "Determines how many hits are required to win (e.g., 20 means 5 hits to destroy 100 health)."
    },
    {
      "name": "enemy_damage_per_hit",
      "type": "number",
      "default": 15,
      "variation_range": "10-25",
      "gameplay_effect": "Determines how quickly the player loses if they don't deploy fast enough."
    }
  ],
  "acceptance_criteria": [
    "Must be a single HTML file with no external dependencies.",
    "All required image and audio assets must be base64 encoded inline.",
    "Total file size must be under 5 MB.",
    "Must run smoothly at 60fps on mobile browsers.",
    "Drag and drop must work with both mouse and touch events.",
    "Health bars must accurately reflect current health and trigger the end state at 0."
  ],
  "non_goals_v1": [
    "Parsing or rendering .psb (Photoshop Big) files in the browser (use PNG weapons instead).",
    "Complex physics-based destruction or rigid body simulations.",
    "Multiple unit types or a scrolling unit menu.",
    "Upgrades or mid-battle currency collection."
  ]
}
